mapper.select:
SELECT u.id, u.student_no, u.username, u.real_name, u.email, u.user_type, u.dept_id, d.dept_name, u.avatar_url, u.status, u.last_login_at, u.created_at FROM sys_user u LEFT JOIN sys_dept d ON u.dept_id = d.id AND d.is_deleted = 0 WHERE u.is_deleted = 0
AND (u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR u.student_no LIKE CONCAT('%', #{keyword}, '%'))
AND u.user_type = #{userType}
AND u.dept_id = #{deptId}
AND u.status = #{status}
ORDER BY u.created_at DESC
